mapper.select:
SELECT dcv.id AS id, dcv.school_year AS schoolYear, ss.id AS semesterId, ss.name AS semesterName, ss.department AS department, grade.id AS classGroupId, grade.grade_group_name AS classGroupName, cla.id AS classId, cla.class_name AS className, stu.seat_no AS studentClassNumber, dcv.student_id AS studentId, stu.chinese_name AS studentName, dcv.violation_date AS violationDate, dcv.remark_id AS remarkId, dcv.remark AS remark, dcv.registrant AS registrant FROM dress_code_violation dcv LEFT JOIN student_info stu ON stu.id = dcv.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_semester ss on dcv.semester_id = ss.id WHERE dcv.deleted = 0
AND dcv.school_id = #{reqModel.schoolId}
AND dcv.school_year = #{reqModel.schoolYear}
AND dcv.semester_id = #{reqModel.semesterId}
AND dcv.class_id = #{reqModel.classId}
AND dcv.student_id = #{reqModel.studentId}
AND dcv.remark = #{reqModel.remark}
AND dcv.violation_date >= #{reqModel.startDate}
AND dcv.violation_date <= #{reqModel.endDate}
AND dcv.class_id IN
#{item}
ORDER BY dcv.create_time desc
